@startuml
skinparam classAttributeIconSize 0

class Dummy << (C,#b7d7b7) >> {
  private
  protected
  pkg method()
  public()
}

interface User << (I,#b9b0e6) >> {
  createAccount(AccountType)
  login()
  logout()
}

class Admin << (C,#b7d7b7) >> {
  createService()
  removeAccount()
  removeAccount()
  --
  setHourlyRate()
  setForm(Service.type, customerInfo)
}

class Employee << (C,#b7d7b7) >> {
  createAccount(Employee)
  selectService()
  setBusinessHour()
  boolean processServiceRequest()
  --
  notifyCustomer()
}

class Customer << (C,#b7d7b7) >> {
  createAccount(Customer)
  --
  searchBranch()
  selectService()
  getForm(Service.type).fill()
  submitForm()
  --
  rateBranch()
}

interface Form << (I,#b9b0e6) >> {
  firstName
  lastName
  dateOfBirth
  address
  email
}

abstract class RentalForm << (A,#bfe6ea) >> {
  pickupTime
  returnTime
  licenseType
}

class MovingForm << (C,#b7d7b7) >> {
  startLocation
  endLocation
  numberOfMovers
  numberOfBoxes
}

class carRentalForm << (C,#b7d7b7) >> {
  carType
}

class truckRentalForm << (C,#b7d7b7) >> {
  usageArea
}

Admin -|> User
Employee -|> User
Customer -|> User

RentalForm -|> Form
MovingForm -|> Form

carRentalForm -|> RentalForm
truckRentalForm -|> RentalForm
@enduml
